@* Collects shipping address fields with basic validation *@

<h3>Shipping Information</h3>

<div class="shipping-form">
    <label>
        Name
        <input type="text" value="@shipping.Name"
               @onchange="e => shipping.Name = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Address
        <input type="text" value="@shipping.Address"
               @onchange="e => shipping.Address = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        City
        <input type="text" value="@shipping.City"
               @onchange="e => shipping.City = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Zip Code
        <input type="text" value="@shipping.ZipCode"
               @onchange="e => shipping.ZipCode = e.Value?.ToString() ?? string.Empty" />
    </label>

    @if (!string.IsNullOrEmpty(validationMessage))
    {
        <p class="validation-error">@validationMessage</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback<ShippingInfo> OnNext { get; set; }

    private ShippingInfo shipping = new();
    private string? validationMessage;

    protected override void OnParametersSet()
    {
        shipping = new ShippingInfo
        {
            Name = Shipping.Name,
            Address = Shipping.Address,
            City = Shipping.City,
            ZipCode = Shipping.ZipCode
        };
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(shipping.Name) || string.IsNullOrWhiteSpace(shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await OnNext.InvokeAsync(shipping);
    }
}

@* Collects payment method with Back and Place Order buttons *@

<h3>Payment Information</h3>

<div class="payment-form">
    <label>
        Card Number
        <input type="text" value="@payment.CardNumber"
               @onchange="e => payment.CardNumber = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Expiry Date
        <input type="text" value="@payment.ExpiryDate"
               @onchange="e => payment.ExpiryDate = e.Value?.ToString() ?? string.Empty" />
    </label>

    <div class="button-group">
        <button @onclick="OnBack">Back</button>
        <button @onclick="HandlePlaceOrder">Place Order</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback<PaymentInfo> OnPlaceOrder { get; set; }

    private PaymentInfo payment = new();

    protected override void OnParametersSet()
    {
        payment = new PaymentInfo
        {
            CardNumber = Payment.CardNumber,
            ExpiryDate = Payment.ExpiryDate
        };
    }

    private async Task HandlePlaceOrder()
    {
        await OnPlaceOrder.InvokeAsync(payment);
    }
}

@* Manages wizard step and holds order state. Emits completed order to parent. *@

<div class="checkout-wizard">
    @if (currentStep == Step.Shipping)
    {
        <ShippingStep Shipping="order.Shipping" OnNext="HandleShippingNext" />
    }
    else if (currentStep == Step.Payment)
    {
        <PaymentStep Payment="order.Payment"
                     OnBack="HandleBackToShipping"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order order = new();
    private Step currentStep = Step.Shipping;

    private enum Step { Shipping, Payment }

    private void HandleShippingNext(ShippingInfo shipping)
    {
        order.Shipping = shipping;
        currentStep = Step.Payment;
    }

    private void HandleBackToShipping()
    {
        currentStep = Step.Shipping;
    }

    private async Task HandlePlaceOrder(PaymentInfo payment)
    {
        order.Payment = payment;
        await OnOrderPlaced.InvokeAsync(order);
    }
}

